import json,subprocess,os
from collections import defaultdict

def check(out,scenario,profile,order):
    if os.path.exists(out): os.remove(out)
    cmd=["/usr/local/bin/arena","--scenario",scenario,"--profile",profile,"--order",order,"--out",out]
    r=subprocess.run(cmd,stdout=subprocess.PIPE,stderr=subprocess.PIPE)
    if r.returncode!=0:
        print('run failed',cmd,'rc',r.returncode)
        print(r.stderr.decode())
        return
    ev=json.load(open(out))['events']
    by=defaultdict(int)
    for e in ev:
        by[(e['kind'],e['id'])]+=1
    subs=[e['id'] for e in ev if e['kind']=='submit']
    ok_sub=(subs==list(range(1,len(subs)+1)))
    dups=sum(1 for k,v in by.items() if v>1)
    missing=0
    for i in range(1,len(subs)+1):
        if by[("submit",i)]!=1 or by[("complete",i)]!=1 or by[("notify",i)]!=1:
            missing+=1
    print(scenario,profile,order,'events',len(ev),'N',len(subs),'sub_ok',ok_sub,'dups',dups,'missing',missing)

for sc in ['basic','stress','stress2']:
  for prof in ['steady','burst']:
    for ord in ['a_then_b','b_then_a']:
      check(f'/app/output/{sc}_{prof}_{ord}.json',sc,prof,ord)
